SELECT job_name, elapsed_time, avg_map_time, avg_reduce_time
FROM job_performance
WHERE elapsed_time > 1800;

SELECT node_id, COUNT(task_id) AS total_tasks
FROM task_performance
GROUP BY node_id;

SELECT job_name, avg_reduce_time
FROM job_performance
WHERE avg_reduce_time < (SELECT AVG(avg_reduce_time) FROM job_performance);

SELECT COUNT(*) 
FROM job_details 
WHERE status = 'SUCCEEDED';

SELECT pool_id, pool_name, capacity, max_jobs
FROM pool_config
WHERE capacity > 1000 AND max_jobs > 100;

SELECT job_id, queue_name, (num_maps + num_reducers) AS TasksPerJob
FROM job_performance
ORDER BY TasksPerJob DESC;

SELECT job_name, elapsed_time
FROM job_performance
WHERE job_id = 'job123';

SELECT job_id, job_name, AVG(elapsed_time) AS average_elapsed_time
FROM job_performance
GROUP BY job_id, job_name;

SELECT job_name, avg_map_time 
FROM job_performance 
WHERE avg_map_time > 1000;

SELECT job_id, job_name, AVG(elapsed_time) AS average_elapsed_time
FROM job_performance
GROUP BY job_id;
